import{_ as a,o,c as d,a0 as i}from"./chunks/framework.Cl79jK2u.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),t={name:"changelog.md"};function l(n,e,r,c,s,h){return o(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to Moxie are documented here.</p><h2 id="_0-1-7-2026-03-21" tabindex="-1">[0.1.7] - 2026-03-21 <a class="header-anchor" href="#_0-1-7-2026-03-21" aria-label="Permalink to &quot;[0.1.7] - 2026-03-21&quot;">​</a></h2><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>LaunchAgent installs now prefer the stable <code>moxie</code> path from <code>PATH</code> instead of a versioned Homebrew Cellar path</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>moxie service install</code>, <code>start</code>, <code>stop</code>, <code>uninstall</code>, <code>restart</code>, and <code>reload</code> now print explicit confirmation messages on success</li></ul><h2 id="_0-1-6-2026-03-21" tabindex="-1">[0.1.6] - 2026-03-21 <a class="header-anchor" href="#_0-1-6-2026-03-21" aria-label="Permalink to &quot;[0.1.6] - 2026-03-21&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>moxie service install</code> and <code>moxie service uninstall</code> for native service definition management</li><li>Optional service install/start flow during <code>moxie init</code></li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>moxie init</code> can now collect a default service working directory when installing a background service</li></ul><h2 id="_0-1-5-2026-03-21" tabindex="-1">[0.1.5] - 2026-03-21 <a class="header-anchor" href="#_0-1-5-2026-03-21" aria-label="Permalink to &quot;[0.1.5] - 2026-03-21&quot;">​</a></h2><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Windows cross-build compatibility for the macOS launchd reload path</li></ul><h2 id="_0-1-4-2026-03-21" tabindex="-1">[0.1.4] - 2026-03-21 <a class="header-anchor" href="#_0-1-4-2026-03-21" aria-label="Permalink to &quot;[0.1.4] - 2026-03-21&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>macOS <code>launchd</code> support for <code>moxie service start|stop|restart|reload|status</code></li><li>LaunchAgent documentation for <code>~/Library/LaunchAgents/io.github.1broseidon.moxie.plist</code></li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>macOS service control now follows the per-user LaunchAgent model instead of failing through <code>systemctl</code></li></ul><h2 id="_0-1-3-2026-03-21" tabindex="-1">[0.1.3] - 2026-03-21 <a class="header-anchor" href="#_0-1-3-2026-03-21" aria-label="Permalink to &quot;[0.1.3] - 2026-03-21&quot;">​</a></h2><h3 id="changed-3" tabindex="-1">Changed <a class="header-anchor" href="#changed-3" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Service lifecycle commands now live under <code>moxie service ...</code> instead of top-level <code>moxie start|stop|restart|reload|status</code></li><li>Non-Linux platforms now get a clear service-manager error instead of attempting to invoke <code>systemctl</code></li></ul><h2 id="_0-1-2-2026-03-21" tabindex="-1">[0.1.2] - 2026-03-21 <a class="header-anchor" href="#_0-1-2-2026-03-21" aria-label="Permalink to &quot;[0.1.2] - 2026-03-21&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Top-level <code>moxie start</code>, <code>stop</code>, <code>restart</code>, <code>reload</code>, and <code>status</code> commands for user service control</li><li>In-process <code>SIGHUP</code> reload support for <code>moxie serve</code> so config and backend definitions can be reloaded without exiting the process</li></ul><h3 id="changed-4" tabindex="-1">Changed <a class="header-anchor" href="#changed-4" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Backend prompts now frame Claude, Codex, and other backends as operating on behalf of Moxie</li><li>Capability descriptions are guided toward local CLI behavior and user-facing Moxie features instead of harness-centric language</li><li><code>poll</code> and <code>cursor</code> are now documented as operator/debug commands instead of primary user commands</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Release workflow can now be manually dispatched for an existing tag</li><li>Homebrew tap publishing path was validated and backfilled</li><li>Prompt injection tests now allow the backend identity suffix added to system prompts</li></ul><h2 id="_0-1-0-2026-03-20" tabindex="-1">[0.1.0] - 2026-03-20 <a class="header-anchor" href="#_0-1-0-2026-03-20" aria-label="Permalink to &quot;[0.1.0] - 2026-03-20&quot;">​</a></h2><p>Initial public release.</p><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Telegram transport with long polling, HTML formatting, photo handling, and file attachments</li><li>Slack transport with Socket Mode, mrkdwn formatting, and thread support</li><li>Multi-backend dispatch via oneagent (Claude, Codex, Gemini, Pi, OpenCode)</li><li><code>/model</code> command to switch backends and models per conversation</li><li><code>/think</code> command for reasoning effort control (low/medium/high)</li><li><code>/cwd</code> command with named workspaces</li><li><code>/new</code> and <code>/threads</code> for thread management</li><li><code>/compact</code> for thread compaction</li><li>Schedules with one-shot (<code>--in</code>, <code>--at</code>) and recurring (<code>--cron</code>) triggers</li><li>Subagent delegation with synthesis back to parent conversation</li><li>Paragraph-aware message chunking for long responses</li><li>Activity status messages during dispatch</li><li>Job persistence and recovery across restarts</li><li>systemd service support</li></ul>',34)])])}const g=a(t,[["render",l]]);export{m as __pageData,g as default};
